// ═══ QR KOD & FİZİKSEL ENTEGRASYON (§5.1) ═════════════════════════════════
// Rapor: Fiziksel DokunSay kapsülleri ile QR kod/kamera entegrasyonu
const QR_SYSTEM = {
  // QR koddan gelen komutlar — fiziksel kapsüllardaki etiketler
  commands: {
    "DOKUNSAY-START": { action: "startMode", desc: "Modu başlat" },
    "DOKUNSAY-COUNT": { action: "counting", desc: "Sayma modunu başlat" },
    "DOKUNSAY-ADD": { action: "addition", desc: "Toplama modunu başlat" },
    "DOKUNSAY-SUB": { action: "subtraction", desc: "Çıkarma modunu başlat" },
    "DOKUNSAY-MUL": { action: "timesTable", desc: "Çarpma modunu başlat" },
    "DOKUNSAY-SUBIT": { action: "subitizing", desc: "Sanbil modunu başlat" },
    "DOKUNSAY-COMPARE": { action: "comparison", desc: "Karşılaştırma modunu başlat" },
    "DOKUNSAY-PART": { action: "partWhole", desc: "Parça-bütün modunu başlat" },
    "DOKUNSAY-BUILD": { action: "buildNumber", desc: "Sayı oluşturma modunu başlat" },
    "DOKUNSAY-PATTERN": { action: "patternAB", desc: "Örüntü modunu başlat" },
    "DOKUNSAY-PLACE": { action: "placeValue", desc: "Basamak değeri modunu başlat" },
    "DOKUNSAY-SET": { action: "setActivity", desc: "Etkinlik paketi yükle" },
    "DOKUNSAY-AR": { action: "ar", desc: "AR deneyimini başlat" },
  },
  // Kamera erişim durumu
  hasCameraSupport: typeof navigator !== "undefined" && !!navigator.mediaDevices?.getUserMedia,
  // QR algılama (basitleştirilmiş — gerçek uygulamada jsQR lib kullanılır)
  parseQR: (data) => {
    if (!data || !data.startsWith("DOKUNSAY-")) return null;
    const parts = data.split("|");
    const cmd = QR_SYSTEM.commands[parts[0]];
    if (!cmd) return null;
    return { ...cmd, params: parts.slice(1) };
  },
};

