// Yolculuk ilerlemesini hesapla
const getJourneyProgress = (path, modeStats) => {
  if (!path) return { stops: [], currentIdx: 0, nextMode: null };
  const stops = path.stops.map((stop, idx) => {
    const modesPlayed = stop.modes.filter(m => modeStats[m]?.total > 0);
    const totalGames = stop.modes.reduce((sum, m) => sum + (modeStats[m]?.total || 0), 0);
    const totalCorrect = stop.modes.reduce((sum, m) => sum + (modeStats[m]?.correct || 0), 0);
    const acc = totalGames > 0 ? Math.round((totalCorrect / totalGames) * 100) : 0;
    const gamesPlayed = stop.modes.reduce((sum, m) => sum + (modeStats[m]?.games || 0), 0);
    // Durak tamamlandı mı?
    const req = stop.unlockReq;
    const complete = modesPlayed.length === stop.modes.length && gamesPlayed >= (req?.gamesMin || 2) && acc >= (req?.accMin || 50);
    // Durak açık mı? (önceki durak tamamlanmış veya ilk durak)
    const prevComplete = idx === 0 ? true : null; // will be set in loop below
    return { ...stop, idx, modesPlayed, totalGames, acc, gamesPlayed, complete };
  });
  // Set unlocked status
  for (let i = 0; i < stops.length; i++) {
    if (i === 0) stops[i].unlocked = true;
    else stops[i].unlocked = stops[i - 1].complete;
  }
  // Find current stop (first unlocked but not complete)
  const currentIdx = stops.findIndex(s => s.unlocked && !s.complete);
  const current = currentIdx >= 0 ? stops[currentIdx] : stops[stops.length - 1];
  // Find next recommended mode within current stop
  let nextMode = null;
  if (current && !current.complete) {
    // Prefer unplayed modes first, then lowest accuracy
    const unplayed = current.modes.filter(m => !modeStats[m]?.total);
    if (unplayed.length > 0) nextMode = unplayed[0];
    else {
      // All played → recommend lowest accuracy
      nextMode = current.modes.reduce((best, m) => {
        const acc = modeStats[m]?.total > 0 ? modeStats[m].correct / modeStats[m].total : 0;
        const bestAcc = modeStats[best]?.total > 0 ? modeStats[best].correct / modeStats[best].total : 0;
        return acc < bestAcc ? m : best;
      }, current.modes[0]);
    }
  }
  return { stops, currentIdx: currentIdx >= 0 ? currentIdx : stops.length - 1, nextMode, allComplete: stops.every(s => s.complete) };
};

const gmi = (id) => { for (const cat of Object.values(CATEGORIES)) if (cat.modes[id]) return cat.modes[id]; return null; };

