// Mod → gezegen eşleşmesi (hangi modun hangi gezegende olduğunu hızlı bul)
const getModePlanet = (modeId) => {
  for (const [catKey, cat] of Object.entries(CATEGORIES)) {
    if (cat.modes[modeId]) return GALAXY_THEME[catKey] || null;
  }
  return null;
};

