const getMathInsight = (mode, isCorrect, question, correctAnswer) => {
  const pool = MATH_INSIGHTS[mode] || MATH_INSIGHTS.default;
  const msgs = isCorrect ? pool.correct : pool.wrong;
  const base = msgs[Math.floor(Math.random() * msgs.length)];
  // Enrich with MATH_INSIGHT_EXTRAS from modeStories (pedagogical extras)
  const extraInsight = MATH_INSIGHT_EXTRAS.getInsightFor?.(mode);
  const enrichedBase = extraInsight && Math.random() > 0.6 ? `${base}\n💡 ${extraInsight}` : base;
  // Context-aware enrichment: incorporate actual question numbers for deeper pedagogy
  if (!question || Math.random() > 0.55) return enrichedBase; // 45% chance to show contextual insight
  const q = question;
  const ca = correctAnswer;
  // CRA progression micro-tips — connect concrete ↔ representational ↔ abstract
  const craTip = (concrete, representational, abstract) => {
    const r = Math.random();
    return r < 0.35 ? concrete : r < 0.7 ? representational : abstract;
  };
  try {
    if (isCorrect) {
      if (q.type === "addition" && q.num1 != null && q.num2 != null) {
        const bigger = Math.max(q.num1, q.num2), smaller = Math.min(q.num1, q.num2);
        const tips = [
          `${q.num1} + ${q.num2} = ${ca} — toplama iki grubu birleştirir!`,
          `${bigger}'den başlayıp ${smaller} tane saydın — verimli strateji!`,
          ca <= 10 ? `${ca} — 10'luk çerçeveye sığıyor!` : `${ca} = 10 + ${ca - 10} — 10'u aşarak topladın!`,
          // CRA deepening
          craTip(
            `Somut: ${q.num1} pul + ${q.num2} pul = ${ca} pul — birleştir ve say!`,
            `Görsel: Sayı doğrusunda ${bigger}'den ${smaller} adım ilerle → ${ca}!`,
            `Soyut: ${q.num1} + ${q.num2} = ${ca} — değişme özelliği: ${q.num2} + ${q.num1} de aynı!`
          ),
          // Strategy awareness
          smaller <= 3 ? `Sayarak topladın: ${bigger}... ${Array.from({length: smaller}, (_, i) => bigger + i + 1).join(", ")} → ${ca}!`
            : ca <= 20 && bigger <= 10 ? `10'un arkadaşını düşün: ${bigger} + ${10 - bigger} = 10, sonra +${smaller - (10 - bigger)} = ${ca}!`
            : `Parçala: ${q.num1} + ${q.num2} = ${ca} — zihninden de yapabilirsin!`,
        ];
        return tips[Math.floor(Math.random() * tips.length)];
      }
      if (q.type === "subtraction" && q.num1 != null && q.num2 != null) {
        const tips = [
          `${q.num1} − ${q.num2} = ${ca} — ters düşünce: ${q.num2} + ${ca} = ${q.num1}!`,
          ca <= 3 ? `${q.num1}'den ${q.num2} adım geriye saydın!` : `Toplama ile düşündün: ${q.num2} + ? = ${q.num1} → ${ca}!`,
          craTip(
            `Somut: ${q.num1} puldan ${q.num2} tane çıkar — kalan ${ca}!`,
            `Görsel: Sayı doğrusunda ${q.num1}'den ${q.num2} adım geri → ${ca}!`,
            `Soyut: ${q.num1} − ${q.num2} = ${ca} ↔ ${q.num2} + ${ca} = ${q.num1} — sayı ailesi!`
          ),
        ];
        return tips[Math.floor(Math.random() * tips.length)];
      }
      if (q.type === "makeTen" && q.current != null) {
        const tips = [`${q.current} + ${ca} = 10 — 10'un arkadaşlarını biliyorsun!`, `10'un sayı bağı: ${q.current} ve ${ca} her zaman 10 eder — bu güçlü bir araç!`, `Bu bilgi ileride çok işe yarar: ${q.current + 5} + ${ca} = ${q.current + 5 + ca} hesabında 10'a tamamla stratejisi!`];
        return tips[Math.floor(Math.random() * tips.length)];
      }
      if (q.type === "makeFive" && q.current != null) return `${q.current} + ${ca} = 5 — 5'in bağlarını öğrendin! Bir elin = 5 parmak 🖐️`;
      if (q.type === "partWhole" && q.whole != null && q.part1 != null) {
        const tips = [`${q.whole} = ${q.part1} + ${ca} — sayı bağı kuruldu!`, `Parça-bütün: ${q.whole}'in içinde ${q.part1} ve ${ca} saklanıyor — dekompozisyon gücü!`];
        return tips[Math.floor(Math.random() * tips.length)];
      }
      if (q.type === "missingNumber" && q.num1 != null) return `Gizli sayı ${ca} — denklemi bir terazi gibi düşündün! Cebirsel düşüncenin ilk adımı 🎯`;
      if (q.type === "timesTable" && q.a != null && q.b != null) {
        const a = q.a, b = q.b;
        const tips = [`${a} × ${b} = ${ca} — çarpım tablosu güçleniyor!`];
        if (a === b) tips.push(`${a}² = ${ca} — kare sayı! ${a} satır × ${a} sütun dizi düşün 📐`);
        if (a <= 5 && b <= 5) tips.push(`${a} × ${b}: ${a} tane ${b}'li grup = ${ca} — somut gruplama!`);
        if (a === 9 || b === 9) tips.push(`×9 sırrı: rakamları toplamı hep 9! ${Math.floor(ca/10)} + ${ca%10} = ${Math.floor(ca/10) + ca%10} ✨`);
        return tips[Math.floor(Math.random() * tips.length)];
      }
      if (q.type === "skipCount" && q.step != null) return craTip(
        `${q.step}'er ${q.step}'er saydın — ritmik sayma çarpmanın temelidir!`,
        `Sayı doğrusunda ${q.step}'er atlayarak ilerliyorsun — her atlama bir çarpım!`,
        `Ritmik sayma → çarpma: ${q.step}, ${q.step*2}, ${q.step*3}... = ${q.step}×1, ${q.step}×2, ${q.step}×3... 🎵`
      );
      if (q.type === "halfDouble") return typeof ca === "number" && ca > 0 ? `Sonuç ${ca} — yarılama ve ikiye katlama birbirinin tersi! ×2 ile ÷2 arasında gidip gel 🔄` : base;
      if (q.type === "growingPattern" && q.step != null) return `Her adımda ${q.step > 0 ? "+" : ""}${q.step} — kuralı buldun! Bu fonksiyonel düşünme: n → n${q.step > 0 ? "+" : ""}${q.step} 📈`;
      if (q.type === "conservation") return "Dizilim değişse de sayı korunur — Piaget'nin sayı korunumu ilkesini kavradın!";
      if (q.type === "subitizing" && q.number != null) {
        return q.number <= 4 ? `${ca} — bir bakışta gördün! Algısal sübitizasyon 👁️` : `${ca} — grupları görüp topladın: kavramsal sübitizasyon! 🧩`;
      }
      if (q.type === "bundleTens" && q.tens != null) return `${q.tens} onluk + ${q.ones} birlik = ${q.total} — basamak değerinin temeli: gruplama (unitize)! 📦`;
      if (q.type === "placeValue") return `Rakamın yeri değerini belirler — onluk sistem gücü! Her basamak 10 kat büyütür 🏛️`;
      if (q.type === "arrayDots" && q.rows != null && q.cols != null) return `${q.rows} × ${q.cols} = ${ca} — diziyi 90° döndürsen ${q.cols} × ${q.rows} olur ama sonuç aynı: değişme özelliği! 📐`;
      if (q.type === "equalShare") return `${q.total} ÷ ${q.groups} = ${ca} — paylaştırma modeli: birer birer dağıt, herkes eşit alsın! ⚖️`;
      if (q.type === "divisionBasic" && q.a != null && q.b != null) return `${q.a} ÷ ${q.b} = ${ca} — çarpmayla kontrol: ${q.b} × ${ca} = ${q.a} ✓`;
      if (q.type === "comparison") return "Karşılaştırma sayı hissinin temelidir — nicelik ilişkisini doğru algıladın!";
      if (q.type === "expandForm" && q.number != null) return `${q.number} = ${q.tensVal} + ${q.ones} — açık biçim basamak değerini ortaya koyar!`;
    } else {
      if (q.type === "addition" && q.num1 != null && q.num2 != null) {
        const bigger = Math.max(q.num1, q.num2), smaller = Math.min(q.num1, q.num2);
        return craTip(
          `Somut: ${bigger} pul koy, sonra ${smaller} tane daha ekle — hepsini say → ${ca}!`,
          `Görsel: Sayı doğrusunda ${bigger}'yi bul, ${smaller} adım ilerle → ${ca}!`,
          `${bigger}'den başla ve ${smaller} tane ileriye say → ${ca}!`
        );
      }
      if (q.type === "subtraction" && q.num1 != null && q.num2 != null) {
        return craTip(
          `Somut: ${q.num1} pul koy, ${q.num2} tanesini çıkar — kalan ${ca}!`,
          `Görsel: Sayı doğrusunda ${q.num1}'den ${q.num2} adım geri → ${ca}!`,
          ca <= 3 ? `${q.num1}'den geriye ${q.num2} adım say → ${ca}!` : `Toplama olarak düşün: ${q.num2} + ? = ${q.num1} → ${ca}!`
        );
      }
      if (q.type === "makeTen" && q.current != null) return `10'luk çerçevede ${10 - q.current} boş kutu var → cevap: ${ca}! Ellerini kullan: ${q.current} parmak kalk, kaçı katlı? 🖐️`;
      if (q.type === "makeFive" && q.current != null) return `5'lik çerçevede ${5 - q.current} boş kutu var → cevap: ${ca}! Bir eline bak 🖐️`;
      if (q.type === "timesTable" && q.a != null && q.b != null) {
        const sm = Math.min(q.a, q.b), lg = Math.max(q.a, q.b);
        return craTip(
          `Somut: ${sm} tane grup yap, her gruba ${lg} tane koy — hepsini say → ${ca}!`,
          `Görsel: ${sm} × ${lg} = ${lg}'er ritmik say: ${Array.from({length: Math.min(sm, 4)}, (_, i) => lg * (i + 1)).join(", ")}${sm > 4 ? "..." : ""} → ${ca}!`,
          `${q.a} × ${q.b} = tekrarlı toplama: ${Array(Math.min(sm, 5)).fill(lg).join("+")}${sm > 5 ? "+..." : ""} = ${ca}!`
        );
      }
      if (q.type === "partWhole" && q.whole != null && q.part1 != null) return `${q.whole} − ${q.part1} = ${ca} — bütünden bilinen parçayı çıkar: kalan diğer parça!`;
      if (q.type === "conservation") return "Nesneleri tek tek say — görünüş aldatabilir ama sayı hep aynı kalır!";
      if (q.type === "subitizing") return "Küçük gruplar halinde düşün: 2+3=5 veya 3+3=6 — grupla ve topla!";
      if (q.type === "bundleTens") return "10 tane birliği bir arada düşün = 1 onluk! Ellerini kullan: iki elde 10 parmak = 1 onluk 📦";
      if (q.type === "equalShare") return `Birer birer dağıt: ${q.total} nesneyi ${q.groups} kişiye sırayla ver → herkes ${ca} alır!`;
      if (q.type === "arrayDots" && q.rows != null && q.cols != null) return `Satırları say (${q.rows}), her satırdaki noktaları say (${q.cols}) — ${q.cols}'er ritmik say ${q.rows} kez → ${ca}!`;
    }
  } catch (_) { /* fallback to base */ }
  return enrichedBase;
};

// ═══ ADAPTİF ZORLUK MOTORU ══════════════════════════════════════════════════
// Rapor §2.1: Gerçek zamanlı performans takibi ve otomatik seviye ayarlama
const AdaptiveEngine = {
  // Her mod için performansı değerlendir → önerilen seviye döndür
  suggestLevel: (modeStats, currentLevel) => {
    if (!modeStats || modeStats.played < 2) return currentLevel;
    const recentAcc = modeStats.recentAcc || 0;
    const avgTime = modeStats.avgTime || 5;
    // Çok başarılı + hızlı → seviye artır
    if (recentAcc >= 85 && avgTime < 5 && currentLevel < 7) return currentLevel + 1;
    // Zorlanıyor → seviye düşür
    if (recentAcc < 45 && currentLevel > 1) return currentLevel - 1;
    return currentLevel;
  },
  // Soru içi mikro-adaptasyon: üst üste hata → daha kolay seçenek oluştur
  shouldSimplify: (sessionErrors) => sessionErrors >= 2,
  shouldChallenge: (sessionCorrect) => sessionCorrect >= 3,
  // Performans verisi güncelle
  updateModePerf: (existing, result) => {
    const prev = existing || { played: 0, totalCorrect: 0, totalQ: 0, recentAcc: 50, avgTime: 5, recentResults: [] };
    const recent = [...(prev.recentResults || []).slice(-9), result.acc];
    const recentAcc = recent.reduce((a, b) => a + b, 0) / recent.length;
    return {
      played: prev.played + 1,
      totalCorrect: prev.totalCorrect + result.correct,
      totalQ: prev.totalQ + result.total,
      recentAcc: Math.round(recentAcc),
      avgTime: result.avgTime ? Math.round((prev.avgTime * 0.7 + result.avgTime * 0.3) * 10) / 10 : prev.avgTime,
      recentResults: recent,
      lastPlayed: Date.now(),
      lastLevel: result.level,
    };
  },
  // Modlar arası bilgi haritası — hangi modlar prerequisite
  prerequisites: {
    addition: ["counting"],
    subtraction: ["addition"],
    partWhole: ["addition", "makeFive"],
    trueFalse: ["partWhole", "missingNumber"],
    growingPattern: ["patternAB", "counting"],
    patternTranslate: ["patternAB"],
    wpAdd: ["addition"],
    wpSub: ["subtraction"],
    wpCompare: ["wpAdd", "wpSub", "difference"],
    wpMul: ["repeatAdd", "multiplyVisual"],
    wpDiv: ["equalShare", "divisionBasic"],
    makeTen: ["makeFive"],
    repeatAdd: ["addition"],
    skipCount: ["repeatAdd"],
    timesTable: ["repeatAdd", "skipCount"],
    equalShare: ["repeatAdd"],
    divisionBasic: ["equalShare"],
    mulDivInverse: ["timesTable", "divisionBasic"],
    katConcept: ["multiplyVisual", "timesTable"],
    placeValue: ["bundleTens"],
    expandForm: ["placeValue"],
    composeNumber: ["placeValue"],
  },
  // Öğrencinin hazır olduğu modları belirle
  getReadyModes: (modePerf) => {
    const ready = new Set();
    Object.entries(modePerf).forEach(([mode, data]) => {
      if (data.recentAcc >= 60) ready.add(mode);
    });
    return ready;
  },
};

