// ═══════════════════════════════════════════════════════════════════════════
// FRUSTRASYON ALGILAMA ve DUYGUSAL DESTEK SİSTEMİ (FDS)
// Uzman Konsensüsü: 4/6 uzman — yanlış cevap frustrasyon riski yüksek
// Referans: Käser et al. (2013), Calcularis affect-aware tutoring
// ═══════════════════════════════════════════════════════════════════════════
const FDS = {
  // Frustrasyon seviyesi: 0=sakin, 1=hafif, 2=orta, 3=yüksek
  calcLevel: (consecutiveWrongs, totalWrongs, totalQ, avgResponseTime, lastResponseTimes) => {
    let level = 0;
    // Ardışık yanlışlar — 5-8 yaş için uyarlanmış eşikler
    // Dweck: 2-3 yanlış öğrenme sürecinin doğal parçası, erken müdahale kaçınılmalı
    if (consecutiveWrongs >= 5) level = 3;
    else if (consecutiveWrongs >= 4) level = 2;
    else if (consecutiveWrongs >= 2) level = 1;

    // Yanıt süresi anomalisi: çok hızlı yanıtlar (rastgele tıklama) frustrasyon göstergesi
    if (lastResponseTimes && lastResponseTimes.length >= 4) {
      const recent4 = lastResponseTimes.slice(-4);
      const avgRecent = recent4.reduce((s, t) => s + t, 0) / recent4.length;
      if (avgRecent < 1.0) level = Math.max(level, 2); // < 1.0s = rastgele tıklama
    }

    // Genel başarı oranı çok düşükse
    if (totalQ >= 4 && (totalWrongs / totalQ) > 0.7) level = Math.max(level, 2);

    return Math.min(level, 3);
  },

  // Frustrasyon seviyesine göre büyüme zihniyeti mesajları
  // Dweck (2006): Süreç odaklı geri bildirim > yetenek odaklı
  messages: {
    0: [], // Sakin — ek mesaj gereksiz
    1: [
      "Beynin şu an yeni bağlantılar kuruyor — bu harika! 🧠✨",
      "Zor sorular beynini daha güçlü yapıyor! 💪",
      "Her deneme bir adım ileri! Devam et 🌱",
    ],
    2: [
      "Derin bir nefes al... Hazır olduğunda deneyelim 🧘",
      "Bu konu zor, ama sen öğreniyorsun! Adım adım gidelim 🐢",
      "Hata yapmak çok normal — bilim insanları da böyle öğrenir! 🔬",
      "Yavaşça düşünmek hızlı düşünmekten daha değerli 🌟",
    ],
    3: [
      "Bir mola verelim mi? Bazen dinlenmek beyni güçlendirir! ☕",
      "Çok uğraşıyorsun — bu harika! Ama zorunda değilsin, istersen farklı bir mod deneyelim 🗺️",
      "Hatalar öğrenmenin en doğal parçası. Beraber daha kolay bir adımdan başlayalım mı? 🤝",
    ],
  },

  // Frustrasyon seviyesine göre adaptif müdahaleler
  getIntervention: (level) => {
    if (level <= 0) return null;
    if (level === 1) return { type: "encourage", action: "growthMindsetMsg" };
    if (level === 2) return { type: "simplify", action: "reduceDifficulty", msg: "Kolay soru geliyor — güvenini topla! ✨" };
    return { type: "break", action: "suggestBreakOrModeChange" };
  },

  getMessage: (level) => {
    const msgs = FDS.messages[level];
    if (!msgs || msgs.length === 0) return null;
    return msgs[Math.floor(Math.random() * msgs.length)];
  },
};

// ═══════════════════════════════════════════════════════════════════════════
// EKRAN SÜRESİ YÖNETİCİSİ
// Uzman Konsensüsü: 3/6 uzman — özellikle 5-6 yaş için kritik
// AAP (2016): 5-8 yaş dijital medya 30-60 dk/gün önerisi
// ═══════════════════════════════════════════════════════════════════════════
const ScreenTimeManager = {
  // Yaş grubuna göre önerilen maksimum süre (dakika)
  maxMinutes: { okuloncesi: 20, sinif1: 25, sinif2: 30, sinif3: 35 },

  // Mola hatırlatma aralığı (dakika)
  breakInterval: 15,

  // Mola mesajları — Montessori felsefesi: fiziksel aktivite entegrasyonu
  breakMessages: [
    { msg: "🏃 Mola zamanı! Ayağa kalk ve 10 kez zıpla!", activity: "physical" },
    { msg: "👀 Gözlerini dinlendir! Pencereden dışarı bak ve 3 farklı renk say!", activity: "visual" },
    { msg: "🖐️ Gerçek nesnelerle pratik yap! Masadaki kalem/boncukları say!", activity: "manipulative" },
    { msg: "🧘 Derin nefes al! 4 saniye iç, 4 saniye tut, 4 saniye ver!", activity: "calming" },
    { msg: "💪 Ellerini sık-aç yap! 5 kez sağ, 5 kez sol — motor becerileri güçlendir!", activity: "motor" },
    { msg: "🎵 Bir şarkı söyle veya 10'a kadar ritmik say: 2, 4, 6, 8, 10!", activity: "auditory" },
  ],

  // Fiziksel manipülatif yönlendirme mesajları (Montessori/Reggio entegrasyonu)
  physicalPracticeHints: [
    "💡 İpucu: Evdeki düğmeler, boncuklar veya lego parçalarıyla aynı oyunu gerçek nesnelerle dene!",
    "💡 İpucu: Merdivenleri çıkarken sayarak pratik yap — her basamak bir pul!",
    "💡 İpucu: Sofra hazırlarken kaşık ve çatalları sayarak eşle!",
    "💡 İpucu: Parkta taşları toplayıp ikili ve üçlü gruplar oluştur!",
  ],

  getBreakMessage: () => {
    const msgs = ScreenTimeManager.breakMessages;
    return msgs[Math.floor(Math.random() * msgs.length)];
  },

  getPhysicalHint: () => {
    const hints = ScreenTimeManager.physicalPracticeHints;
    return hints[Math.floor(Math.random() * hints.length)];
  },

  // Günlük kullanım bilgilendirmesi
  getDailySummary: (minutesUsed, ageGroup) => {
    const max = ScreenTimeManager.maxMinutes[ageGroup] || 25;
    const pct = Math.round((minutesUsed / max) * 100);
    if (pct >= 100) return { status: "limit", color: "#ef4444", msg: `Bugünkü ${max} dakikalık hedefine ulaştın! Yarın devam ederiz 🌙`, icon: "⏰" };
    if (pct >= 75) return { status: "warning", color: "#f59e0b", msg: `${max - minutesUsed} dakika kaldı — son bir oyun oynayabilirsin!`, icon: "⏳" };
    return { status: "ok", color: "#22c55e", msg: `Bugün ${minutesUsed} dakika kullandın (önerilen: ${max} dk)`, icon: "✅" };
  },
};

// ═══════════════════════════════════════════════════════════════════════════
// MATEMATİK KAYGISI TAKİP SİSTEMİ
// Uzman Konsensüsü: 2/6 uzman — Ashcraft & Moore (2009), Dowker et al. (2016)
// Davranışsal göstergeler ile kaygı tahmini (self-report mümkün değil 5-8 yaş)
// ═══════════════════════════════════════════════════════════════════════════
const AnxietyTracker = {
  // Davranışsal göstergeler
  indicators: {
    // Yanıt süresi tutarsızlığı (yüksek varyans = kararsızlık/kaygı)
    responseTimeVariance: (times) => {
      if (!times || times.length < 5) return 0;
      const avg = times.reduce((s, t) => s + t, 0) / times.length;
      const variance = times.reduce((s, t) => s + Math.pow(t - avg, 2), 0) / times.length;
      return Math.sqrt(variance); // standart sapma
    },

    // Kaçınma davranışı: belirli modlarda çok düşük oyun sayısı
    avoidancePattern: (modeStats) => {
      const entries = Object.entries(modeStats || {});
      if (entries.length < 3) return [];
      const avgGames = entries.reduce((s, [_, d]) => s + (d.games || 0), 0) / entries.length;
      return entries
        .filter(([_, d]) => (d.games || 0) > 0 && d.total > 0 && (d.correct / d.total) < 0.4)
        .map(([mode]) => mode);
    },

    // Hız bazlı tıklama (rastgele seçim — cognitive avoidance)
    rapidGuessing: (responseTimes) => {
      if (!responseTimes || responseTimes.length < 3) return false;
      const recent = responseTimes.slice(-5);
      const fastClicks = recent.filter(t => t < 1.2).length;
      return fastClicks >= 3; // 5 soruda 3+ çok hızlı yanıt
    },
  },

  // Kaygı seviyesi hesaplama (0-3: düşük, orta, yüksek, kritik)
  calcLevel: (responseTimes, modeStats, consecutiveWrongs) => {
    let score = 0;
    const rtVar = AnxietyTracker.indicators.responseTimeVariance(responseTimes);
    if (rtVar > 8) score += 2;
    else if (rtVar > 5) score += 1;

    if (AnxietyTracker.indicators.rapidGuessing(responseTimes)) score += 2;

    const avoidedModes = AnxietyTracker.indicators.avoidancePattern(modeStats);
    if (avoidedModes.length >= 3) score += 1;

    if (consecutiveWrongs >= 4) score += 1;

    return Math.min(Math.floor(score / 2), 3);
  },

  // Ebeveyn/öğretmen için gösterge
  getReport: (responseTimes, modeStats, consecutiveWrongs) => {
    const level = AnxietyTracker.calcLevel(responseTimes, modeStats, consecutiveWrongs);
    const avoided = AnxietyTracker.indicators.avoidancePattern(modeStats);
    const rapid = AnxietyTracker.indicators.rapidGuessing(responseTimes);

    const labels = ["Düşük 🟢", "Hafif 🟡", "Orta 🟠", "Yüksek 🔴"];
    return {
      level,
      label: labels[level],
      isRapidGuessing: rapid,
      avoidedModes: avoided,
      suggestion: level >= 2
        ? "Çocuğunuz bazı konularda kaygı belirtileri gösteriyor. Daha kolay modlarla başlayıp başarı deneyimi yaşamasını sağlayın. Fiziksel materyallerle pratik yapması faydalı olabilir."
        : level === 1
        ? "Hafif tereddüt gözleniyor. Bu normaldir. Destekleyici ve sabırlı bir tutum sürdürün."
        : "Sağlıklı öğrenme örüntüsü gözleniyor.",
    };
  },
};

// ═══ GÜNLÜK GÖREV SİSTEMİ ══════════════════════════════════════════════════
// Rapor §6.2: Görev sistemi ile bağlılık artırma
const QuestSystem = {
  generateDailyQuests: (stats) => {
    const today = new Date().toISOString().split("T")[0];
    const modesPlayed = Object.keys(stats?.modeStats || {}).length;
    const dayOfWeek = new Date().getDay();
    const totalGames = stats?.totalGames || 0;
    const questPools = [
      // Pool A: Oyun sayısı veya seri — günlük rotasyon
      dayOfWeek % 2 === 0
        ? { id: `streak3_${today}`, type: "streak", target: 3, emoji: "🔥",
            title: "3'lü Yıldız Serisi", desc: "Bir oyunda 3 üst üste doğru cevap ver", reward: 45, progress: 0 }
        : { id: `play3_${today}`, type: "playGames", target: 3, emoji: "🎮",
            title: "3 Görev Tamamla", desc: "Bugün 3 oyun tamamla", reward: 50, progress: 0 },
      // Pool B: Farklı mod — keşif teşviki
      { id: `modes2_${today}`, type: "uniqueModes", target: 2, emoji: "🗺️",
        title: "2 Gezegen Keşfet", desc: "Bugün 2 farklı modda oyna", reward: 40, progress: 0 },
      // Pool C: Başarı oranı veya keşif — deneyime göre
      modesPlayed < 10
        ? { id: `explore_${today}`, type: "newMode", target: 1, emoji: "🌟",
            title: "Yeni Gezegen Keşfet", desc: "Daha önce ziyaret etmediğin bir gezegeni keşfet", reward: 60, progress: 0 }
        : { id: `acc80_${today}`, type: "highAcc", target: 80, emoji: "💎",
            title: "Yıldız Taşı Topla", desc: "Bir görevde %80 üzeri başarıyla yıldız taşı kazan", reward: 60, progress: 0 },
    ];
    // Pool D: Bonus görev — deneyimli oyuncular için
    if (totalGames >= 10 && dayOfWeek % 3 === 0) {
      questPools.push({
        id: `streak5_${today}`, type: "streak", target: 5, emoji: "⚡",
        title: "5'li Şimşek Serisi", desc: "Bir oyunda 5 üst üste doğru cevap ver", reward: 80, progress: 0,
      });
    }
    return { date: today, quests: questPools.slice(0, 4), completed: false };
  },
  updateProgress: (quests, gameResult, stats) => {
    if (!quests?.quests) return quests;
    const updated = { ...quests, quests: quests.quests.map(q => {
      const qc = { ...q };
      if (q.type === "playGames") qc.progress = Math.min(q.target, q.progress + 1);
      else if (q.type === "uniqueModes") {
        const todayModes = new Set(stats?.todayModes || []);
        todayModes.add(gameResult.mode);
        qc.progress = Math.min(q.target, todayModes.size);
      }
      else if (q.type === "newMode" && gameResult.isNew) qc.progress = 1;
      else if (q.type === "highAcc" && gameResult.acc >= 80) qc.progress = 1;
      else if (q.type === "streak" && (gameResult.maxStreak || 0) >= q.target) qc.progress = q.target;
      return qc;
    })};
    updated.completed = updated.quests.every(q => q.progress >= (q.type === "highAcc" || q.type === "newMode" ? 1 : q.target));
    return updated;
  },
  getReward: (quests) => {
    if (!quests?.quests) return 0;
    return quests.quests.filter(q => q.progress >= (q.type === "highAcc" || q.type === "newMode" ? 1 : q.target)).reduce((sum, q) => sum + q.reward, 0);
  },
  // ═══ GÜNLÜK GİRİŞ SERİSİ ═══
  getLoginStreak: (lastLoginDate) => {
    const today = new Date().toISOString().split("T")[0];
    if (!lastLoginDate) return { streak: 1, isNewDay: true, reward: 5, milestone: null };
    if (lastLoginDate === today) return { streak: 0, isNewDay: false, reward: 0, milestone: null };
    const last = new Date(lastLoginDate);
    const now = new Date(today);
    const diffDays = Math.round((now - last) / (1000 * 60 * 60 * 24));
    if (diffDays === 1) {
      const stored = parseInt(safeStorage.get("galaksay_login_streak", "0"));
      const newStreak = stored + 1;
      safeStorage.set("galaksay_login_streak", String(newStreak));
      safeStorage.set("galaksay_last_login", today);
      const baseReward = 5;
      const streakBonus = Math.min(newStreak * 2, 30);
      const reward = baseReward + streakBonus;
      const milestones = {
        3: { emoji: "🔥", title: "3 Gün Serisi!", desc: "Üç gün üst üste oynamaya geldin!", bonus: 15 },
        7: { emoji: "⭐", title: "Haftalık Yıldız!", desc: "Tam bir hafta boyunca her gün oynadın!", bonus: 50 },
        14: { emoji: "💎", title: "İki Hafta Efsanesi!", desc: "14 gün boyunca hiç ara vermedin!", bonus: 100 },
        30: { emoji: "👑", title: "Galaktik Kararlılık!", desc: "30 gün boyunca her gün geldin!", bonus: 250 },
      };
      return { streak: newStreak, isNewDay: true, reward, milestone: milestones[newStreak] || null };
    }
    safeStorage.set("galaksay_login_streak", "1");
    safeStorage.set("galaksay_last_login", today);
    return { streak: 1, isNewDay: true, reward: 5, milestone: null };
  },
};

// ═══ ERİŞİLEBİLİRLİK AYARLARI ═════════════════════════════════════════════
// Rapor §7: Renk körü modu, font boyutu, erişilebilirlik
const A11Y_DEFAULTS = {
  colorBlind: false,    // Renk körü modu: desen tabanlı çip ayrımı
  largeText: false,     // Büyük yazı tipi
  reducedMotion: false, // Azaltılmış animasyon
  highContrast: false,  // Yüksek kontrast
  calmMode: false,      // Sakin mod: tüm animasyonlar + sesler minimize (diskalkuli-uyumlu)
};
// Renk körü modunda çip renkleri: mavi→daire+çizgili, kırmızı→kare+düz
const CB_COLORS = { blue: "#3b82f6", red: "#b45309" }; // Mavi/Turuncu-kahve (deuteranopia safe)
const CB_PATTERNS = { blue: "stripe", red: "dots" };
// §Subitizing: 5'erli gruplarla renk değişimi — bir bakışta miktar algılama
// 1-5: mavi, 6-10: kırmızı, 11-15: mavi, 16-20: kırmızı...
const subColor = (i, a = "blue", b = "red") => Math.floor(i / 5) % 2 === 0 ? a : b;
const subColorHex = (i) => Math.floor(i / 5) % 2 === 0 ? "#3b82f6" : "#dc2626";

// ═══ ERROR BOUNDARY — Uygulama çökmelerini yakalar ═══════════════════════════
class GalaksayErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, errorInfo) { console.error("[GalakSay] Render hatasi:", error, errorInfo); }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", background: "linear-gradient(170deg,#312e81,#4f46e5,#312e81)", fontFamily: "'Nunito',sans-serif", padding: 32, textAlign: "center" }}>
          <div style={{ fontSize: 64, marginBottom: 16, animation: "float1 3s ease-in-out infinite" }}>🚀</div>
          <div style={{ fontSize: 22, fontWeight: 900, color: "#f1f5f9", marginBottom: 8 }}>Bir sorun olustu!</div>
          <div style={{ fontSize: 14, fontWeight: 600, color: "#a5b4fc", marginBottom: 24, maxWidth: 320, lineHeight: 1.6 }}>
            Uzay gemimiz gecici bir turbulansa girdi. Endise etme, hemen duzeltebiliriz!
          </div>
          <button onClick={() => { this.setState({ hasError: false, error: null }); }} style={{
            padding: "14px 36px", borderRadius: 16, border: "none", background: "linear-gradient(135deg,#6d28d9,#7c3aed)", color: "#fff", fontSize: 16, fontWeight: 900, cursor: "pointer", boxShadow: "0 4px 20px rgba(124,58,237,.4)", marginBottom: 12,
          }}>Tekrar Dene</button>
          <button onClick={() => { localStorage.clear(); window.location.reload(); }} style={{
            padding: "10px 24px", borderRadius: 12, border: "1px solid rgba(255,255,255,.2)", background: "transparent", color: "rgba(255,255,255,.6)", fontSize: 12, fontWeight: 700, cursor: "pointer",
          }}>Sifirla ve Yeniden Baslat</button>
          <div style={{ marginTop: 20, fontSize: 10, color: "rgba(255,255,255,.5)", fontWeight: 600 }}>
            Hata: {this.state.error?.message || "Bilinmeyen hata"}
          </div>
        </div>
      );
    }
    return (<>
      <div className="landscape-warn"><span className="lw-icon">📱</span><span className="lw-text">En iyi deneyim icin telefonunu dikey konuma getir!</span></div>
      {this.props.children}
    </>);
  }
}

