  const [fluencyMode, setFluencyMode] = useState(false);
  const [fluencySession, setFluencySession] = useState(null);

  // ═══ v6.0: Üçlü Kodlama Fazı ═══
  const [tripleCodePhase, setTripleCodePhase] = useState(0); // 0=Keşfet, 1=Gör, 2=Yaz, 3=Bağla
  const [showTripleCode, setShowTripleCode] = useState(false);

  // ═══ v5.4: Yanılgı Diagnostiği (Misconception Detection) ═══
  // Araştırma: Meister Cody Calcularis — hata pattern analizi ile yanılgı tespiti
  const misconceptionLogRef = useRef([]); // Son 20 hata kaydı
  const detectMisconception = useCallback((question, givenAnswer, correctAnswer) => {
    if (!question || givenAnswer === correctAnswer) return null;
    const qt = question.type;
    const given = Number(givenAnswer);
    const correct = Number(correctAnswer);
    if (isNaN(given) || isNaN(correct)) return null;

    let misconception = null;
    // 1. Off-by-one: 1 fazla/eksik sayma (kardinalite prensibi hatası)
    if (Math.abs(given - correct) === 1 && ["counting","subitizing","chipGuess","rodBack","fivesFrame","tensFrame"].includes(qt)) {
      misconception = { type: "offByOne", desc: "1 fazla/eksik: Son saydığın sayı toplam miktarı verir (kardinalite)", icon: "🔢" };
    }
    // 2. Reversal: Onlar-birler yer değişimi (placeValue hatası)
    else if (["placeValue","bundleTens","composeNumber","expandForm"].includes(qt)) {
      const revGiven = Number(String(given).split("").reverse().join(""));
      if (revGiven === correct) {
        misconception = { type: "digitReversal", desc: "Basamak karışıklığı: Soldaki rakam ONluklar, sağdaki BİRlikler", icon: "🔄" };
      }
    }
    // 3. Operation confusion: Toplama yerine çıkarma veya tersi
    else if (["addition","countOnAdd"].includes(qt) && question.a && question.b) {
      if (given === question.a - question.b || given === Math.abs(question.a - question.b)) {
        misconception = { type: "opConfusion", desc: "İşlem karışıklığı: Bu bir toplama sorusu — iki grubu birleştir!", icon: "➕" };
      }
    }
    else if (["subtraction"].includes(qt) && question.a && question.b) {
      if (given === question.a + question.b) {
        misconception = { type: "opConfusion", desc: "İşlem karışıklığı: Bu bir çıkarma sorusu — farkı bul!", icon: "➖" };
      }
    }
    // 4. Conservation error: Dizilime aldanma
    else if (qt === "conservation" && given !== correct) {
      misconception = { type: "conservation", desc: "Dizilim aldatabilir! Nesneleri tek tek say — yayılmış = daha fazla değil", icon: "👁️" };
    }
    // 5. Counting all instead of counting on
    else if (qt === "countOnAdd" && question.a && question.b) {
      if (given === question.b) {
        misconception = { type: "countAll", desc: "Büyük sayıdan başla, küçük sayı kadar ileriye say — hepsini saymana gerek yok!", icon: "🎯" };
      }
    }

    if (misconception) {
      misconceptionLogRef.current = [...misconceptionLogRef.current.slice(-19), { ...misconception, qt, given, correct, ts: Date.now() }];
    }
    return misconception;
  }, []);

  // ═══ YENİ: Frustrasyon Algılama, Ekran Süresi, Kaygı Takibi ═══
