  const [arRodCount, setArRodCount] = useState(5);
  const [arRod2Count, setArRod2Count] = useState(3); // compare/add: ikinci kapsül
  const [arChips, setArChips] = useState([]); // free/count mode: [{x,y,id,color}]
  const [arCount, setArCount] = useState(0); // count mode
