  const [arError, setArError] = useState(null);
  const [arRodPos, setArRodPos] = useState({ x: 50, y: 40 }); // % position
  const [arRod2Pos, setArRod2Pos] = useState({ x: 50, y: 70 }); // ikinci kapsül
