  const [arMatchAnswer, setArMatchAnswer] = useState(null);
  const [arMeasurePoints, setArMeasurePoints] = useState([]); // measure: [{x,y}]
  const arContainerRef = useRef(null);

  // ═══ KAPTAN GÜNLÜĞÜ & GÖREV ARKI & ESERLER ═══
  const [captainsLog, setCaptainsLog] = useState([]); // [{entry, date, planet, acc}]
  const [showCaptainsLog, setShowCaptainsLog] = useState(false); // günlük gösterim
  const [unlockedArtifacts, setUnlockedArtifacts] = useState([]); // kazanılan eser id'leri
  const [showArtifactUnlock, setShowArtifactUnlock] = useState(null); // yeni eser bildirimi
  const [missionArcProgress, setMissionArcProgress] = useState(null); // görev arkı ilerlemesi
  const [showCrewRescue, setShowCrewRescue] = useState(null); // mürettebat kurtarma animasyonu
  const [showTransition, setShowTransition] = useState(null); // warp geçiş mesajı

  // ── QR Tarama State ──
  const qrVideoRef = useRef(null);
  const qrCanvasRef = useRef(null);
  const qrScanIntervalRef = useRef(null);
  const [qrReady, setQrReady] = useState(false);
  const [qrError, setQrError] = useState(null);
  const [qrScanning, setQrScanning] = useState(false);
  const [qrLastScan, setQrLastScan] = useState(null); // { code, mode, time }
  const [qrScanHistory, setQrScanHistory] = useState([]);
  const [qrFlash, setQrFlash] = useState(false); // yeşil flash animasyonu

  // ── AR Ek State (görev sistemi) ──
  const [arTask, setArTask] = useState(null); // { type, a, b, answer, prompt }
  const [arTaskAnswer, setArTaskAnswer] = useState(null);
  const [arTaskScore, setArTaskScore] = useState(0);
  const [arSubResult, setArSubResult] = useState(null); // çıkarma sonucu gösterimi

  // ═══ NuMap ENTEGRASYON STATE ═══
  const [numapProfile, setNumapProfile] = useState(null); // NuMap mudahale plani
  const [numapModes, setNumapModes] = useState(null); // onerilen mod listesi
  const [numapStartMode, setNumapStartMode] = useState(null); // baslangic modu
  const [numapSupport, setNumapSupport] = useState(null); // destek düzeyi
  const [manualName, setManualName] = useState("");
  const [manualRisk, setManualRisk] = useState("medium");
  const [manualWeak, setManualWeak] = useState([]);
  const [manualStrong, setManualStrong] = useState([]);

  // NuMap profili yüklendiğinde destek düzeyini ve başlangıç seviyesini ayarla
  const applyNumapProfile = useCallback((profile) => {
    if (!profile) return;
    setNumapProfile(profile);
    const modes = NumapProfile.getRecommendedModes(profile);
    if (modes.length > 0) setNumapModes(modes);
    if (modes.length > 0) setNumapStartMode(modes[0]);
    setNumapSupport(NumapProfile.getSupportLevel(profile));
    // Başlangıç seviyesini NuMap'e göre kalibre et
    const startLvl = NumapProfile.getStartLevel(profile);
    if (startLvl) setLevel(startLvl);
  }, []);

  // NuMap URL parametreleri + localStorage okuma
  useEffect(() => {
    try {
      const params = new URLSearchParams(window.location.search);
      if (params.get("from") === "numap") {
        const modes = params.get("modes");
        const start = params.get("start");
        const lvl = params.get("level");
        if (modes) setNumapModes(modes.split(",").filter(Boolean));
        if (start) setNumapStartMode(start);
        if (lvl) setLevel(parseInt(lvl, 10) || 1);
        setNumapProfile({ source: "deeplink", modes: modes ? modes.split(",") : [], start: start, level: lvl });
      }
      // localStorage'dan NuMap plan kontrol
      const keys = Object.keys(localStorage).filter(k => k.startsWith("numap_intervention_"));
      if (keys.length > 0) {
        const latest = keys.sort().pop();
        const plan = SafeStorage.getJSON(latest);
        if (plan) {
          const validated = NumapProfile.validate(plan);
          if (validated) {
            applyNumapProfile(validated);
          } else if (plan.priority) {
            // Eski format uyumluluğu
            const allModes = [];
            plan.priority.forEach(p => { if (p.modes) p.modes.forEach(m => { if (allModes.indexOf(m) < 0) allModes.push(m); }); });
            plan.secondary?.forEach(s => { if (s.modes) s.modes.forEach(m => { if (allModes.indexOf(m) < 0) allModes.push(m); }); });
            if (allModes.length > 0 && !numapModes) {
              setNumapProfile(plan);
              setNumapModes(allModes);
              if (plan.priority.length > 0 && plan.priority[0].modes?.[0]) {
                setNumapStartMode(plan.priority[0].modes[0]);
              }
            }
          }
        }
      }
    } catch (e) { console.warn("NuMap integration init error:", e); }
  }, []);

  // NuMap JSON plan import fonksiyonu
  const importNumapPlan = useCallback((jsonStr) => {
    try {
      const plan = typeof jsonStr === "string" ? JSON.parse(jsonStr) : jsonStr;
      // Yeni format: NumapProfile.validate ile doğrula
      const validated = NumapProfile.validate(plan);
      if (validated) {
        applyNumapProfile(validated);
        const childKey = validated.child?.code || "imported";
        SafeStorage.set("numap_intervention_" + childKey, JSON.stringify(validated));
        return true;
      }
      // Eski format uyumluluğu
      if (!plan || plan.source !== "numap") return false;
      setNumapProfile(plan);
      const allModes = [];
      if (plan.priority) plan.priority.forEach(p => { if (p.modes) p.modes.forEach(m => { if (allModes.indexOf(m) < 0) allModes.push(m); }); });
      if (plan.secondary) plan.secondary.forEach(s => { if (s.modes) s.modes.forEach(m => { if (allModes.indexOf(m) < 0) allModes.push(m); }); });
      setNumapModes(allModes);
      if (plan.priority?.length > 0 && plan.priority[0].modes?.[0]) {
        setNumapStartMode(plan.priority[0].modes[0]);
      }
      const childKey = plan.child?.code || "imported";
      SafeStorage.set("numap_intervention_" + childKey, JSON.stringify(plan));
      return true;
    } catch (e) { console.warn("NuMap plan import error:", e); return false; }
  }, []);

  // Manuel NuMap profil oluşturma fonksiyonu
  const createManualProfile = useCallback(({ name, risk, weakAreas, strongAreas }) => {
    const profile = NumapProfile.createManual({ name, risk, weakAreas, strongAreas });
    applyNumapProfile(profile);
    const childKey = profile.child?.code || "manual";
    SafeStorage.set("numap_intervention_" + childKey, JSON.stringify(profile));
    return profile;
  }, [applyNumapProfile]);

  // AR kamera yönetimi — screen "ar" olduğunda başlat, çıkınca kapat
  useEffect(() => {
    if (screen !== "ar") return;
    let stream = null;
    let cancelled = false;
    setArReady(false); setArError(null);
    (async () => {
      try {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: "environment", width: { ideal: 1280 }, height: { ideal: 720 } },
          audio: false,
        });
        if (cancelled) { stream.getTracks().forEach(t => t.stop()); return; }
        setArStream(stream);
        if (arVideoRef.current) {
          arVideoRef.current.srcObject = stream;
          arVideoRef.current.play();
        }
        setArReady(true);
      } catch (e) {
        if (!cancelled) {
          console.error("AR Camera error:", e);
          setArError(e.name === "NotAllowedError" ? "Kamera izni verilmedi. Lütfen tarayıcı ayarlarından izin verin." : "Kamera başlatılamadı: " + e.message);
        }
      }
    })();
    return () => {
      cancelled = true;
      if (stream) stream.getTracks().forEach(t => t.stop());
      setArStream(null); setArReady(false);
    };
  }, [screen]);

  // ── QR Tarama kamera + BarcodeDetector ──
  useEffect(() => {
    if (screen !== "qrScan") return;
    let stream = null;
    let cancelled = false;
    setQrReady(false); setQrError(null); setQrScanning(false); setQrLastScan(null);

    const QR_MODE_MAP = {
      "DOKUNSAY-COUNT": { mode: "counting", label: "Göktaşı Say!" },
      "DOKUNSAY-ADD": { mode: "addition", label: "Güç Birleştir!" },
      "DOKUNSAY-SUB": { mode: "subtraction", label: "Enerji Ayır!" },
      "DOKUNSAY-MUL": { mode: "timesTable", label: "Strateji Ustası!" },
      "DOKUNSAY-SUBIT": { mode: "subitizing", label: "Şimşek Bakışı!" },
      "DOKUNSAY-COMPARE": { mode: "comparison", label: "Gezegen Düellosu!" },
      "DOKUNSAY-PART": { mode: "partWhole", label: "Bağlantı Kur!" },
      "DOKUNSAY-BUILD": { mode: "buildNumber", label: "Yıldız Taşı Yapısı!" },
      "DOKUNSAY-PATTERN": { mode: "patternAB", label: "Galaktik Desen!" },
      "DOKUNSAY-PLACE": { mode: "placeValue", label: "Basamara!" },
      "DOKUNSAY-START": { mode: null, label: "Genel Başlat" },
      "DOKUNSAY-SET": { mode: null, label: "Etkinlik Paketi" },
      "DOKUNSAY-AR": { mode: null, label: "AR Deneyimi", screen: "ar" },
    };

    const handleScan = (code) => {
      if (cancelled) return;
      const parts = code.split("|");
      const cmd = parts[0];
      const mapping = QR_MODE_MAP[cmd];
      if (!mapping) return;

      sfx("correct");
      setQrFlash(true);
      setTimeout(() => setQrFlash(false), 600);

      const scanEntry = { code: cmd, label: mapping.label, time: Date.now() };
      setQrLastScan(scanEntry);
      setQrScanHistory(prev => [scanEntry, ...prev].slice(0, 10));

      if (ttsOn) TTS.speak(mapping.label + " başlatılıyor!");

      // Navigasyon (kısa gecikme ile kullanıcıya feedback göster)
      setTimeout(() => {
        if (cancelled) return;
        if (mapping.screen) {
          navigateTo(mapping.screen);
        } else if (mapping.mode) {
          setGameMode(mapping.mode);
          navigateTo("levelSelect");
        }
      }, 1200);
    };

    (async () => {
      try {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: "environment", width: { ideal: 640 }, height: { ideal: 480 } },
          audio: false,
        });
        if (cancelled) { stream.getTracks().forEach(t => t.stop()); return; }
        if (qrVideoRef.current) {
          qrVideoRef.current.srcObject = stream;
          await qrVideoRef.current.play();
        }
        setQrReady(true); setQrScanning(true);

        // BarcodeDetector API kullan (Chrome 83+, Edge, Android)
        const hasBarcodeDetector = typeof BarcodeDetector !== "undefined";
        if (hasBarcodeDetector) {
          const detector = new BarcodeDetector({ formats: ["qr_code"] });
          qrScanIntervalRef.current = setInterval(async () => {
            if (!qrVideoRef.current || qrVideoRef.current.readyState < 2) return;
            try {
              const barcodes = await detector.detect(qrVideoRef.current);
              for (const bc of barcodes) {
                if (bc.rawValue && bc.rawValue.startsWith("DOKUNSAY-")) {
                  handleScan(bc.rawValue);
                  clearInterval(qrScanIntervalRef.current);
                  setQrScanning(false);
                  break;
                }
              }
            } catch (e) { /* scan frame error — ignore */ }
          }, 300);
        } else {
          // Fallback: canvas tabanlı elle tarama (BarcodeDetector yoksa bilgi göster)
          setQrError("fallback");
        }
      } catch (e) {
        if (!cancelled) {
          setQrError(e.name === "NotAllowedError"
            ? "Kamera izni verilmedi. Tarayıcı ayarlarından izin verin."
            : "Kamera başlatılamadı: " + e.message);
        }
      }
    })();

    return () => {
      cancelled = true;
      if (qrScanIntervalRef.current) clearInterval(qrScanIntervalRef.current);
      if (stream) stream.getTracks().forEach(t => t.stop());
      setQrReady(false); setQrScanning(false);
    };
  }, [screen]);

  const [onboardStep, setOnboardStep] = useState(0);
