    if (t === "equalShare") return `${t}-${q.total}-${q.groups}`;
    if (t === "groupCount") return `${t}-${q.total}-${q.perGroup}`;
    if (t === "halfDouble") return `${t}-${q.number}-${q.subType}`;
    if (t === "divisionBasic") return `${t}-${q.a}-${q.b}`;
    if (t === "mulDivInverse") return `${t}-${q.factor1}-${q.factor2}-${q.askPart}`;
    if (t === "katConcept") return `${t}-${q.base}-${q.multiplier}-${q.direction}`;
    if (t === "bundleTens") return `${t}-${q.total}`;
