                border: `1px solid ${perfKey === "perfect" ? "rgba(251,191,36,.2)" : perfKey === "excellent" ? "rgba(124,58,237,.15)" : "rgba(99,102,241,.1)"}`,
                animation: "fadeUp .5s ease .3s both",
